#include <string>
#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    bool validPalindrome(string s, int k)
    {
        int left = 0, right = s.size() - 1;
        while (left < right)
        {
            if (s[left] != s[right])
            {
                if (k > 0)
                {
                    k--;
                    left++;
                }
                else
                {
                    return false;
                }
            }
            left++, right--;
        }
        return true;
    }
};

int main()
{
    string s;
    cin >> s;
    int k;
    cin >> k;
    Solution solution;
    cout << solution.validPalindrome(s, k) << endl;
    return 0;
}
